<template><section class="card"><h3>{{ t('promptops.editor.promptContent') }}</h3><label>System Prompt <VariableAwareInput v-model="system" :show-count="true" :autosize="{minRows:6,maxRows:16}"/></label><small v-if="errors.systemPrompt" class="error">{{ errors.systemPrompt }}</small><label>User Prompt <VariableAwareInput v-model="user" :show-count="true" :autosize="{minRows:7,maxRows:18}"/></label><small v-if="errors.userPrompt" class="error">{{ errors.userPrompt }}</small></section></template>
<script setup lang="ts">import{computed}from'vue';import{useI18n}from'vue-i18n';import VariableAwareInput from '../../variable-extraction/VariableAwareInput.vue';const props=defineProps<{systemPrompt:string;userPrompt:string;errors:Record<string,string>}>();const emit=defineEmits<{(e:'update:systemPrompt',v:string):void;(e:'update:userPrompt',v:string):void}>();const{t}=useI18n();const system=computed({get:()=>props.systemPrompt,set:v=>emit('update:systemPrompt',v)});const user=computed({get:()=>props.userPrompt,set:v=>emit('update:userPrompt',v)});</script>
<style scoped>.card{display:grid;gap:13px}.card label{display:grid;gap:7px;font-weight:600}.error{color:#dc2626}</style>
